var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......저게 침식 억제기인가?","JPN":"……あれが侵食抑制装置？","ENG":"...Is that the Inhibitor?","TWN":"……那就是侵蝕抑制器嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"꽤 큰데?","JPN":"結構大きいな。","ENG":"It's bigger than I thought.","TWN":"還挺大的嘛。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"자, 잘은 모르지만 구 관리국의 유물을 발굴해서 중추 시스템으로 사용했다고 해요.","JPN":"く、詳しくはないのですが、旧管理局の遺物を掘り起こしてコアシステムにしたそうです。","ENG":"I-I heard they discovered an artifact from the Old Administration and used it as the central system.","TWN":"我、我雖然也不太清楚，但據說是挖掘到舊管理局的遺物後，把它當作中樞系統來使用的。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"이 정도의 고출력 이터니움 에너지를 추출해서 제어할 수 있는 건 관리국의 로스트 테크놀러지뿐이거든요.","JPN":"これほどの高出力のエタニウムエネルギーを抽出して\\nコントロールできるのは、管理局のロスト・テクノロジーだけなんです。","ENG":"Only the lost technology of the former Administration is capable of extracting and controlling this amount of high-powered Eternium energy.","TWN":"只有管理局的失落科技，才能做到萃取並控制這麼高功率永恆之金能量。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아직은 실험적인 기술이지만 이걸 분석해서 기술복원이 끝나는 대로 각 대도시에 설치될 거라고......","JPN":"今のところは実験的な技術ですが、これの分析と\\n技術復元が済み次第、大都市に設置されるそうで……","ENG":"It's still in the experimental stage, but I hear they're going to install one in every major city once they analyze and restore the technology...","TWN":"雖然這種技術還在試驗中，但聽說分析完畢後，會復原這個技術並設置在各大城市中……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"구 관리국......?","JPN":"旧管理局……？","ENG":"The Old Administration...?","TWN":"舊管理局？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"처, 처음 들으시나요? 구 관리국이라는 건 그러니까......","JPN":"は、初耳ですか？　旧管理局というのは、ですから……","ENG":"You've never heard of them before? So the Old Administration is...","TWN":"妳、妳是第一次聽說嗎？舊管理局是……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아냐. 괜찮아. 지난번에 너희 대장에게 들은 적이 있어.","JPN":"いや、大丈夫。それはこの前、あなたたちの隊長に聞いたことがあるから。","ENG":"No. It's okay. Your cap explained it to me.","TWN":"沒關係，不用解釋了。我之前有聽妳的隊長說過。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그런데 저게 그것과 관련이 있다는 거지?","JPN":"……ところで、あれがそれと関係してるってことだよね？","ENG":"...So you're saying this thing is connected to the Old Administration?","TWN":"……但舊管理局和這件事有什麼關係？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"이, 일단은 그렇다고 들었어요......","JPN":"い、一応、そうだと聞きました……","ENG":"Y-yes, at least that's what I've heard...","TWN":"總、總之我是這麼聽說的……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐! 엎드려!!","JPN":"おい、伏せろ！！","ENG":"Hey! Get down!","TWN":"喂！趴下！！"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"미나야, 괜찮아?!","JPN":"ミナちゃん、大丈夫！？","ENG":"Mina! Are you okay?!","TWN":"米娜，妳沒事吧？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 뭐가 날아온 거야?","JPN":"な、なに？　何が飛んできたの？","ENG":"Huh? What the heck was that?","TWN":"怎、怎麼回事？什麼東西飛過來了？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"핀리 하이어드 놈들이다.","JPN":"フィンリー・ハイアードの奴らだ。","ENG":"It's Finley Hired.","TWN":"是芬利傭兵團那些傢伙。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"벌써 따라붙다니, 빠른걸?","JPN":"こんなに早く追いつくとはな。","ENG":"They're pretty fast... catching up with us already.","TWN":"他們竟然已經追上來了，動作很快嘛？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>HQ! 놈들을 발견했다! 위치는 침식 억제기 근처, 즉시 지원 바란다!</color>","JPN":"<color=#ffd34c>HQ！　ターゲットを発見！　位置は侵食抑制装置付近。直ちに支援願う！</color>","ENG":"<color=#ffd34c>HQ! We found them! They're at the Inhibitor. Send reinforcements right away!</color>","TWN":"<color=#ffd34c>HQ！發現那些傢伙了！位置是侵蝕抑制器附近，請求立刻支援！</color>"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MERCENARIES_VOICE_NULL_SQUARD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 HQ, 지원 병력을 보내겠다.</color>","JPN":"<color=#ffd34c>こちらHQ、支援兵力を派遣する。</color>","ENG":"<color=#ffd34c>This is HQ. We'll send reinforcements your way.</color>","TWN":"<color=#ffd34c>這裡是HQ，將派遣支援兵力。</color>"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"MERCENARIES_VOICE_NULL_SQUARD","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};